sql:
SELECT partition_name, partition_status, created_at, COUNT(partition_id) AS total_partitions
FROM data_partitions
GROUP BY partition_status, partition_name, created_at;

SELECT partition_name, partition_type, partition_status, created_at
FROM data_partitions
WHERE partition_status = 'active';

SELECT COUNT(*) AS active_partitions_count 
FROM data_partitions 
WHERE partition_status = 'active';

external_knowledge:
- The 'Load' metric refers to the amount of data or workload being processed by each partition; 
- Complexity levels are categorized based on the amount of data, computational resources, or other relevant factors;
- Actions and their corresponding dates refer to maintenance, updates, or other events related to the data partitions.

sql:
SELECT partition_name, partition_status 
FROM data_partitions 
WHERE partition_id = 1;

SELECT partition_name, num_k_partitions AS max_partitions
FROM data_partitions
WHERE num_k_partitions = (SELECT MAX(num_k_partitions) FROM data_partitions);

SELECT metric_name, AVG(metric_value) AS average_metric_value
FROM partition_metrics
GROUP BY metric_name;

SELECT COUNT(*) 
FROM partition_history 
WHERE strftime('%Y', action_date) = '2023';

SELECT COUNT(*) 
FROM partition_levels 
WHERE level_value > 0;

SELECT metric_name, AVG(metric_value) AS avg_metric_value
FROM partition_metrics
WHERE partition_id = 1;

SELECT AVG(metric_value) AS average_value
FROM partition_metrics
WHERE metric_name = 'Efficiency';

SELECT partition_id
FROM data_partitions
ORDER BY updated_at DESC;
